std::vector<Token> Lexer::tokenize()
{
    std::vector<Token> tokens;
    for (;;) {
        Token token = next();
        bool done = token.type == Token_Type::END_OF_FILE;
        tokens.push_back(token);
        if (done)
            break;
    }
    return tokens;
}

